module ProgrammableTokens.OffChain.AikenProgrammableTokenScripts (
    aikenAlwaysFailScript,
    aikenProtocolParamsMintingScript,
    aikenProtocolParamsSpendingScript,
    aikenIssuanceCborHexMintingScript,
    aikenIssuanceCborHexSpendingScript,
    aikenDirectoryNodeMintingScript,
    aikenDirectoryNodeSpendingScript,
    aikenProgrammableLogicBaseScript,
    aikenProgrammableLogicGlobalScript,
    aikenProgrammableLogicMintingScript,
) where

import Cardano.Api qualified as C
import Convex.Aiken.Blueprint (
    fromCardanoApiScriptToProgram,
    fromProgramToCardanoApiScript,
 )
import Convex.PlutusLedger.V1 (transPolicyId)
import Data.ByteString.Base16 qualified as Base16
import Data.ByteString.Char8 qualified as BS8
import Data.ByteString.Short qualified as SBS
import Plutarch.Evaluate (applyArguments)
import Plutarch.Script (Script (Script, unScript))
import PlutusLedgerApi.Common (Data, builtinDataToData)
import PlutusLedgerApi.V1 qualified as PV1
import PlutusLedgerApi.V3 (
    BuiltinByteString,
    Credential,
    CurrencySymbol,
    TxOutRef,
 )
import PlutusTx qualified

-- | Aiken version of @validators/always_fail.ak@.
aikenAlwaysFailScript :: BuiltinByteString -> C.PlutusScript C.PlutusScriptV3
aikenAlwaysFailScript nonce =
    applyDataArguments alwaysFailScript [toPlutusData nonce]

-- | Mirrors the Plutarch protocol-params spending script convention.
aikenProtocolParamsSpendingScript :: C.PlutusScript C.PlutusScriptV3
aikenProtocolParamsSpendingScript =
    aikenAlwaysFailScript (PV1.toBuiltin BS8.empty)

-- | Mirrors the Plutarch issuance-cbor-hex spending script convention.
aikenIssuanceCborHexSpendingScript :: C.PlutusScript C.PlutusScriptV3
aikenIssuanceCborHexSpendingScript =
    aikenAlwaysFailScript (PV1.toBuiltin $ BS8.pack "deadbeef")

aikenProtocolParamsMintingScript :: TxOutRef -> C.PlutusScript C.PlutusScriptV3
aikenProtocolParamsMintingScript utxoRef =
    applyDataArguments
        protocolParamsMintingScript
        [ toPlutusData utxoRef
        , toPlutusData $ scriptHashBytes aikenProtocolParamsSpendingScript
        ]

aikenIssuanceCborHexMintingScript :: TxOutRef -> C.PlutusScript C.PlutusScriptV3
aikenIssuanceCborHexMintingScript utxoRef =
    applyDataArguments
        issuanceCborHexMintingScript
        [ toPlutusData utxoRef
        , toPlutusData $ scriptHashBytes aikenIssuanceCborHexSpendingScript
        ]

aikenDirectoryNodeMintingScript :: TxOutRef -> TxOutRef -> C.PlutusScript C.PlutusScriptV3
aikenDirectoryNodeMintingScript utxoRef issuanceUtxoRef =
    applyDataArguments
        directoryNodeMintingScript
        [ toPlutusData utxoRef
        , toPlutusData $ scriptCurrencySymbol $ aikenIssuanceCborHexMintingScript issuanceUtxoRef
        ]

aikenDirectoryNodeSpendingScript :: CurrencySymbol -> C.PlutusScript C.PlutusScriptV3
aikenDirectoryNodeSpendingScript protocolParamsCs =
    applyDataArguments
        directoryNodeSpendingScript
        [toPlutusData protocolParamsCs]

aikenProgrammableLogicBaseScript :: Credential -> C.PlutusScript C.PlutusScriptV3
aikenProgrammableLogicBaseScript globalCredential =
    applyDataArguments
        programmableLogicBaseScript
        [toPlutusData globalCredential]

aikenProgrammableLogicGlobalScript :: CurrencySymbol -> C.PlutusScript C.PlutusScriptV3
aikenProgrammableLogicGlobalScript protocolParamsCs =
    applyDataArguments
        programmableLogicGlobalScript
        [toPlutusData protocolParamsCs]

aikenProgrammableLogicMintingScript :: Credential -> Credential -> C.PlutusScript C.PlutusScriptV3
aikenProgrammableLogicMintingScript programmableLogicBase mintingLogicCredential =
    applyDataArguments
        programmableLogicMintingScript
        [ toPlutusData programmableLogicBase
        , toPlutusData mintingLogicCredential
        ]

applyDataArguments :: C.PlutusScript C.PlutusScriptV3 -> [Data] -> C.PlutusScript C.PlutusScriptV3
applyDataArguments script args =
    let program =
            either
                (error . ("Could not deserialise embedded Aiken script: " <>))
                id
                (fromCardanoApiScriptToProgram script)
        applied = applyArguments (Script program) args
     in fromProgramToCardanoApiScript (unScript applied)

toPlutusData :: (PlutusTx.ToData a) => a -> Data
toPlutusData =
    builtinDataToData . PlutusTx.toBuiltinData

scriptHashBytes :: C.PlutusScript C.PlutusScriptV3 -> BuiltinByteString
scriptHashBytes =
    PV1.toBuiltin
        . C.serialiseToRawBytes
        . C.hashScript
        . C.PlutusScript C.PlutusScriptV3

scriptCurrencySymbol :: C.PlutusScript C.PlutusScriptV3 -> CurrencySymbol
scriptCurrencySymbol =
    transPolicyId
        . C.scriptPolicyId
        . C.PlutusScript C.PlutusScriptV3

scriptFromHex :: String -> C.PlutusScript C.PlutusScriptV3
scriptFromHex =
    C.PlutusScriptSerialised
        . SBS.toShort
        . Base16.decodeLenient
        . BS8.pack

